dtsPropsFor.Ic:
/** Which glyph to draw. Unknown names render an empty 24x24 svg. */
name:
  | 'arrow-right' | 'arrow-up-right' | 'arrow-up' | 'arrow-down'
  | 'trending-up' | 'shield-check' | 'map-pin' | 'home' | 'building'
  | 'sprout' | 'leaf' | 'pie-chart' | 'bar-chart' | 'file-text' | 'lock'
  | 'users' | 'bell' | 'search' | 'check' | 'check-circle'
  | 'chevron-down' | 'chevron-right' | 'chevron-left' | 'plus' | 'settings'
  | 'download' | 'calendar' | 'sun' | 'moon' | 'menu' | 'x' | 'wallet'
  | 'play' | 'youtube' | 'filter' | 'external-link' | 'mail' | 'clock'
  | 'dollar' | 'layers' | 'eye' | 'more' | 'logout' | 'linkedin';
/** Width and height in px. Default 20. */
size?: number;
/** Stroke width. Default 1.75 — the house weight; raise for large display icons. */
stroke?: number;
/** Merged over the built-in `flex: none`. */
style?: React.CSSProperties;
className?: string;

dtsPropsFor.Photo:
/** Caption drawn over the bottom of the frame. */
label?: string;
/** Smaller line under `label`. */
sublabel?: string;
/** CSS height of the frame. Default '100%'. */
h?: string | number;
/** CSS border-radius. Default 'var(--radius-2xl)'. */
radius?: string;
/** Image URL. Without it the frame renders as a tinted placeholder. */
src?: string;

dtsPropsFor.SectionHead:
/** Small uppercase label above the title. */
eyebrow?: string;
/** The heading itself. */
title?: string;
/** Supporting paragraph under the title. */
sub?: string;
/** Text alignment. 'center' also constrains width to 46ch and centres the block. Default 'left'. */
align?: 'left' | 'center';

dtsPropsFor.HomeSectionHead:
/** Small uppercase label above the title. */
eyebrow?: string;
/** The heading itself. */
title?: string;
/** Supporting paragraph under the title. */
sub?: string;
/** Text alignment. 'center' also constrains width to 46rem and centres the block. Default 'center'. */
align?: 'left' | 'center';
/** Render the title in the editorial serif (Newsreader, forest-700) instead of the UI sans. */
serif?: boolean;

dtsPropsFor.InvestModal:
/** Whether the modal is shown. Renders nothing when false. */
open?: boolean;
/** Called on backdrop click, close button and Escape. */
onClose?: () => void;
